function useFireCollection(colName) {
  const [data, setData] = useState([]);
  const [loaded, setLoaded] = useState(false);
  useEffect(() => {
    const unsub = onSnapshot(collection(db, colName), snap => {
      const docs = snap.docs.map(d => ({ ...d.data(), _id: d.id }));
      setData(docs); setLoaded(true);
    }, () => setLoaded(true));
    return unsub;
  }, [colName]);
  return [data, loaded];
}
async function fireAdd(col, data) { const { _id, ...c } = data; await addDoc(collection(db, col), { ...c, _ts: Date.now() }); }
async function fireUpdate(col, id, data) { const { _id, ...c } = data; await updateDoc(doc(db, col, id), { ...c, _ts: Date.now() }); }
async function fireDelete(col, id) { await deleteDoc(doc(db, col, id)); }

